#include "pytorch_npu_helper.hpp"

at::Tensor instance_norm_impl_npu(const at::Tensor& self, double eps) {
    at::Tensor result = at::empty_like(self);
    EXEC_NPU_CMD(aclnnInstanceNormCustom, self, static_cast<float>(eps), result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("instance_norm_custom", &instance_norm_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("instance_norm_custom", &instance_norm_impl_npu, "InstanceNorm (InstanceNormCustom on NPU)");
}
